  # --- Step 1: Precomputation ---
  # S[d] stores a sorted list of all numbers v in [0, 5000] such that digit_sum(v) = d
  S = Array(51) { Array(Int64)() }

  for v in 0...5000 {
    d = digit_sum(v)
    S[d].push(v)
  }

  N = digitSum.size
  if N == 0 { return 0 }

  # --- Step 2: DP Initialization (i=0) ---
  # DP_prev maps value v (Int64) -> count (Int64)
  DP_prev = Hash(Int64, Int64)

  d0 = digitSum[0]
  if d0 > 50 { return 0 } # Safety check based on precomputation range

  for v in S[d0] {
    DP_prev[v] = 1
  }

  # --- Step 3: DP Iteration (i=1 to N-1) ---
  for i in 1...N-1 {
    d_prev = digitSum[i-1]
    d_curr = digitSum[i]

    if d_curr > 50 || d_prev > 50 { 
      # If required digit sums are outside the range we precomputed (0-50)
      return 0 
    }

    DP_curr = Hash(Int64, Int64)
    D_prev = S[d_prev]
    D_curr = S[d_curr]

    C = 0 # Cumulative sum of counts from DP_prev
    p_prev = 0

    # D_curr is already sorted
    for v in D_curr {
      # Update C: sum DP_prev[u] for all u in D_prev such that u <= v
      while p_prev < D_prev.size && D_prev[p_prev] <= v {
        u = D_prev[p_prev]

        count_u = DP_prev[u] ?? 0 # Count for previous state ending in u

        C = (C + count_u) % MOD
        p_prev += 1
      }

      DP_curr[v] = C
    }

    DP_prev = DP_curr
  }

  # --- Step 4: Final Result ---
  total_count = 0
  for count in DP_prev.values {
    total_count = (total_count + count) % MOD
  }

  return total_count
}
